import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [tab, setTab] = useState('users');
  const [themeTrigger, setThemeTrigger] = useState(false);

  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data));
    API.get('/admin/posts').then(res => setPosts(res.data));
    API.get('/admin/comments').then(res => setComments(res.data));
  }, []);

  useEffect(() => {
    const handleThemeChange = () => setThemeTrigger(prev => !prev);
    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  const removePost = async (id) => {
    if (!window.confirm("Permanently delete this post? This cannot be undone.")) return;
    try {
      await API.delete(`/posts/${id}`); 
      setPosts(posts.filter(p => p._id !== id));
    } catch (err) {
      alert("Error deleting post.");
    }
  };

  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(comments.filter(c => c._id !== id));
  };

  const viewPost = (postId) => {
    navigate(`/posts/${postId}`);
  };

  const isDark = document.body.classList.contains('dark-mode');

  // UPDATED DESIGN PALETTE
  const colors = {
    bgPink: '#FAE8ED',      
    cardPink: '#FBD5E0',    
    tablePink: '#F9B2C9',   
    darkGreen: '#043414',   
    white: '#FFFFFF',
    borderPink: '#E8A0B5'
  };

  const styles = {
    page: {
      backgroundColor: isDark ? '#1a0510' : colors.bgPink,
      minHeight: '100vh',
      padding: '60px 20px',
      fontFamily: '"Segoe UI", Roboto, Helvetica, Arial, sans-serif',
      display: 'flex',
      justifyContent: 'center',
    },
    container: {
      width: '100%',
      maxWidth: '1100px',
      backgroundColor: isDark ? '#2e091e' : colors.cardPink,
      padding: '40px',
      borderRadius: '50px',
      boxShadow: '20px 20px 60px rgba(0,0,0,0.05), -20px -20px 60px rgba(255,255,255,0.8)',
      textAlign: 'center',
      border: `2px solid ${colors.white}`
    },
    heading: {
      fontSize: '52px',
      fontWeight: '950',
      color: colors.darkGreen,
      marginBottom: '40px',
      textTransform: 'uppercase',
      letterSpacing: '6px'
    },
    tabs: {
      display: 'flex',
      justifyContent: 'center',
      gap: '15px',
      marginBottom: '40px',
    },
    tabButton: {
      padding: '12px 35px',
      borderRadius: '50px',
      border: `3px solid ${colors.darkGreen}`,
      cursor: 'pointer',
      fontWeight: '800',
      fontSize: '16px',
      backgroundColor: colors.white,
      color: colors.darkGreen,
      transition: 'all 0.2s ease',
    },
    activeTab: {
      backgroundColor: colors.darkGreen,
      color: colors.white,
      transform: 'scale(1.05)',
    },
    tableWrapper: {
      overflow: 'hidden',
      borderRadius: '25px',
      border: `3px solid ${colors.darkGreen}`,
      backgroundColor: colors.tablePink,
    },
    table: {
      width: '100%',
      borderCollapse: 'collapse',
    },
    th: {
      padding: '22px',
      backgroundColor: colors.darkGreen,
      color: colors.white,
      textAlign: 'center',
      fontSize: '15px',
      textTransform: 'uppercase',
      letterSpacing: '2px',
      borderRight: `1px solid ${colors.borderPink}`
    },
    td: {
      padding: '18px',
      borderBottom: `2px solid ${colors.borderPink}`,
      borderRight: `2px solid ${colors.borderPink}`,
      color: colors.darkGreen,
      fontSize: '17px',
      fontWeight: '700',
    },
    actionCell: {
      display: 'flex',
      gap: '12px',
      justifyContent: 'center',
      alignItems: 'center'
    },
    btnGreen: {
      padding: '10px 22px',
      borderRadius: '12px',
      border: 'none',
      backgroundColor: colors.darkGreen,
      color: colors.white,
      cursor: 'pointer',
      fontWeight: '700',
      fontSize: '13px',
      display: 'flex',
      alignItems: 'center',
      gap: '6px',
      boxShadow: '0 4px 0px #021a0a',
      transition: 'transform 0.1s ease'
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Admin Portal</h2>

        <div style={styles.tabs}>
          {['users', 'posts', 'comments'].map((t) => (
            <button
              key={t}
              onClick={() => setTab(t)}
              style={{ ...styles.tabButton, ...(tab === t ? styles.activeTab : {}) }}
            >
              {t.toUpperCase()}
            </button>
          ))}
        </div>

        <div style={styles.tableWrapper}>
          <table style={styles.table}>
            <thead>
              {tab === 'users' && (
                <tr>
                  <th style={styles.th}>Username</th>
                  <th style={styles.th}>Email</th>
                  <th style={styles.th}>Status</th>
                  <th style={{...styles.th, borderRight: 'none'}}>Action</th>
                </tr>
              )}
              {tab === 'posts' && (
                <tr>
                  <th style={styles.th}>Title</th>
                  <th style={styles.th}>Author</th>
                  <th style={{...styles.th, borderRight: 'none'}}>Actions</th>
                </tr>
              )}
              {tab === 'comments' && (
                <tr>
                  <th style={styles.th}>User</th>
                  <th style={styles.th}>Comment</th>
                  <th style={{...styles.th, borderRight: 'none'}}>Action</th>
                </tr>
              )}
            </thead>
            <tbody>
              {tab === 'users' && users.map(u => (
                <tr key={u._id}>
                  <td style={styles.td}>{u.name}</td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.status.toUpperCase()}</td>
                  <td style={{...styles.td, borderRight: 'none'}}>
                    <div style={styles.actionCell}>
                      <button style={styles.btnGreen} onClick={() => toggleStatus(u._id)}>
                        {u.status === 'active' ? '🚫 Ban User' : '✅ Unban User'}
                      </button>
                    </div>
                  </td>
                </tr>
              ))}

              {tab === 'posts' && posts.map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.author?.name || 'Unknown'}</td>
                  <td style={{...styles.td, borderRight: 'none'}}>
                    <div style={styles.actionCell}>
                      <button style={styles.btnGreen} onClick={() => viewPost(p._id)}>
                        👁 View
                      </button>
                      <button style={styles.btnGreen} onClick={() => removePost(p._id)}>
                        🗑 Delete
                      </button>
                    </div>
                  </td>
                </tr>
              ))}

              {tab === 'comments' && comments.map(c => (
                <tr key={c._id}>
                  <td style={styles.td}>{c.author?.name}</td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={{...styles.td, borderRight: 'none'}}>
                    <div style={styles.actionCell}>
                      <button style={styles.btnGreen} onClick={() => deleteComment(c._id)}>
                        🗑 Remove
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminPage;
